1	const PROCESSING_FEE = 5;
2	const FIRST_CONTRACT_INSURANCE_RATE = 0.1;
3	
4	type Item = { type: string };
5	type QuoteStep = { op: "quote"; items: Item[] };
6	type Step = QuoteStep;
7	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
8	
9	const BASE_PREMIUM: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	};
13	
14	const quotePremium = (items: Item[]): number => {
15	  const itemBaseSum = items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
16	  const firstContractInsurance = itemBaseSum * FIRST_CONTRACT_INSURANCE_RATE;
17	  return Math.ceil(itemBaseSum + firstContractInsurance + PROCESSING_FEE);
18	};
19	
20	export const runScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
21	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
22	  return { results };
23	};
